let idx = index as int;

// Re-state both runs' page_array `forall|i|` ensures so z3 has them in scope
// with explicit, post-specific triggers (the two original quantifiers were
// triggered on disjoint terms — `post1_self_.page_array@[i]` and
// `post2_self_.page_array@[i]` — so they never lined up).
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != idx ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != idx ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise equality on the page_array views between the two runs.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == idx {
        // At idx, every Page field is determined: the non-`mappings` fields
        // equal pre_self_'s, and `mappings` equals the input `mapping` in
        // both runs. Chain through pre_self_ to align post1 and post2.
        assert(post1_self_.page_array@[idx].addr =~= pre_self_.page_array@[idx].addr);
        assert(post2_self_.page_array@[idx].addr =~= pre_self_.page_array@[idx].addr);
        assert(post1_self_.page_array@[idx].state =~= pre_self_.page_array@[idx].state);
        assert(post2_self_.page_array@[idx].state =~= pre_self_.page_array@[idx].state);
        assert(post1_self_.page_array@[idx].is_io_page =~= pre_self_.page_array@[idx].is_io_page);
        assert(post2_self_.page_array@[idx].is_io_page =~= pre_self_.page_array@[idx].is_io_page);
        assert(post1_self_.page_array@[idx].rev_pointer =~= pre_self_.page_array@[idx].rev_pointer);
        assert(post2_self_.page_array@[idx].rev_pointer =~= pre_self_.page_array@[idx].rev_pointer);
        assert(post1_self_.page_array@[idx].ref_count =~= pre_self_.page_array@[idx].ref_count);
        assert(post2_self_.page_array@[idx].ref_count =~= pre_self_.page_array@[idx].ref_count);
        assert(post1_self_.page_array@[idx].owning_container
            =~= pre_self_.page_array@[idx].owning_container);
        assert(post2_self_.page_array@[idx].owning_container
            =~= pre_self_.page_array@[idx].owning_container);
        assert(post1_self_.page_array@[idx].mappings =~= mapping);
        assert(post2_self_.page_array@[idx].mappings =~= mapping);
        assert(post1_self_.page_array@[idx].io_mappings
            =~= pre_self_.page_array@[idx].io_mappings);
        assert(post2_self_.page_array@[idx].io_mappings
            =~= pre_self_.page_array@[idx].io_mappings);
    } else {
        // Off-index: both runs leave page_array[i] unchanged from pre.
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Lift the pointwise Page equality to Seq extensional equality on the views.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
